package com.example.kafkastreaming.web;

import com.example.kafkastreaming.service.EventPublisher;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.Instant;
import java.util.UUID;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventPublisher publisher;

    public EventController(EventPublisher publisher) {
        this.publisher = publisher;
    }

    @PostMapping
    public ResponseEntity<String> publish(@RequestBody(required = false) String payload) {
        String eventId = UUID.randomUUID().toString();
        String body = (payload == null || payload.isBlank())
                ? "{\"eventId\":\"" + eventId + "\",\"ts\":\"" + Instant.now() + "\",\"message\":\"hello\"}"
                : payload;
        publisher.publish(eventId, body);
        return ResponseEntity.accepted().body(eventId);
    }
}

package com.example.kafkastreaming.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class EventPublisher {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final String topic;

    public EventPublisher(KafkaTemplate<String, String> kafkaTemplate,
                          @Value("${app.kafka.topic:events.platform}") String topic) {
        this.kafkaTemplate = kafkaTemplate;
        this.topic = topic;
    }

    public void publish(String key, String eventJson) {
        kafkaTemplate.send(topic, key, eventJson);
    }
}

package com.example.kafkastreaming.service;

import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    @KafkaListener(topics = "${app.kafka.topic:events.platform}", groupId = "${spring.kafka.consumer.group-id:event-platform-consumer}")
    public void onMessage(ConsumerRecord<String, String> record) {
        String key = record.key();
        String value = record.value();
        String topic = record.topic();
        int partition = record.partition();
        long offset = record.offset();

        System.out.println("Consumed message: topic=" + topic
                + " partition=" + partition
                + " offset=" + offset
                + " key=" + key
                + " value=" + value);
    }
}

